// Nó 02: Valida HMAC SHA-256, filtra fromMe/evento/mídia
// NÃO checa ia_ativa — isso é Nó 03
const crypto = require('crypto');
const body = $input.first().json;
const headers = body.headers || {};

const secret = $env.EVOLUTION_HMAC_SECRET;
const sig = headers['x-evolution-signature'] || headers['X-Evolution-Signature'] || '';
if (secret && sig) {
  const payload = JSON.stringify(body.body !== undefined ? body.body : body);
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');
  if (expected !== sig) throw new Error('HMAC inválido — requisição rejeitada');
}

const fromMe = body?.data?.key?.fromMe;
if (fromMe === true) return [];

const event = body?.event || '';
if (!['messages.upsert', 'message'].includes(event)) return [];

const msgData = body?.data?.message || {};
const remotejid = body?.data?.key?.remoteJid || '';
const pushName = body?.data?.pushName || '';
if (!remotejid) return [];

const conversation = msgData?.conversation || msgData?.extendedTextMessage?.text || '';
if (!conversation) {
  const isMedia = !!(msgData?.imageMessage || msgData?.audioMessage || msgData?.videoMessage || msgData?.documentMessage);
  if (isMedia) return [{ json: { action: 'media_only', remotejid, pushName } }];
  return [];
}

return [{ json: { action: 'process', remotejid, pushName, content: conversation } }];

// Nó 03: Checa kill_switch global + ia_ativa por lead (Supabase)
// Retorna [] para STOP (fluxo para silenciosamente)
const { remotejid, pushName, content } = $input.first().json;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const h = { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` };

const cfgRes = await fetch(`${supabaseUrl}/rest/v1/clientes_config?select=kill_switch&limit=1`, { headers: h });
if (!cfgRes.ok) throw new Error(`Supabase clientes_config error ${cfgRes.status}`);
const cfgData = await cfgRes.json();
if (cfgData?.[0]?.kill_switch === true) return [];

const leadRes = await fetch(
  `${supabaseUrl}/rest/v1/leads?select=ia_ativa&remotejid=eq.${encodeURIComponent(remotejid)}&limit=1`,
  { headers: h }
);
if (!leadRes.ok) throw new Error(`Supabase leads error ${leadRes.status}`);
const leadData = await leadRes.json();
const lead = Array.isArray(leadData) ? leadData[0] : null;
if (lead && lead.ia_ativa === false) return [];

return [{ json: { remotejid, pushName, content } }];

