// Nó 05: Persistir mensagem do lead ANTES de chamar Anthropic (regra canônica)
// UPSERT leads + INSERT chat_messages(role=user)
const { remotejid, pushName, content } = $input.first().json;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const h = {
  apikey: supabaseKey,
  Authorization: `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
};

const leadRes = await fetch(`${supabaseUrl}/rest/v1/leads`, {
  method: 'POST',
  headers: { ...h, Prefer: 'resolution=merge-duplicates' },
  body: JSON.stringify({ remotejid, nome: pushName || null }),
});
if (!leadRes.ok && leadRes.status !== 409) {
  throw new Error(`Falha ao persistir lead (${leadRes.status}): ${await leadRes.text()}`);
}

const msgRes = await fetch(`${supabaseUrl}/rest/v1/chat_messages`, {
  method: 'POST',
  headers: h,
  body: JSON.stringify({ remotejid, role: 'user', content }),
});
if (!msgRes.ok) {
  throw new Error(`Falha ao persistir mensagem (${msgRes.status}): ${await msgRes.text()}`);
}

return [{ json: { remotejid, pushName, content } }];

// Nó 06: Carrega últimas 20 msgs (ordem cronológica) + perfil do lead
const { remotejid, pushName, content } = $input.first().json;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const h = { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` };

const histRes = await fetch(
  `${supabaseUrl}/rest/v1/chat_messages?remotejid=eq.${encodeURIComponent(remotejid)}&order=created_at.desc&limit=20&select=role,content`,
  { headers: h }
);
if (!histRes.ok) throw new Error(`Supabase history error ${histRes.status}`);
const histData = await histRes.json();
const history = Array.isArray(histData) ? histData.reverse() : [];

const perfilRes = await fetch(
  `${supabaseUrl}/rest/v1/leads_perfil?remotejid=eq.${encodeURIComponent(remotejid)}&select=objetivo,historico_treino,restricoes,frequencia,turno_preferido&limit=1`,
  { headers: h }
);
if (!perfilRes.ok) throw new Error(`Supabase perfil error ${perfilRes.status}`);
const perfilData = await perfilRes.json();
const perfil = Array.isArray(perfilData) && perfilData.length > 0 ? perfilData[0] : {};

return [{ json: { remotejid, pushName, content, history, perfil } }];

// Nó 07b: Retoma loop Anthropic após execução do nó nativo Google Calendar
// Recebe: $input = Google Calendar event; orig = contexto do Nó 07
const calEvent = $input.first().json;
const orig = $('Nó 07 — Call Anthropic com Tool Loop').item.json;
const remotejid = orig.remotejid;

let calResult;
if (calEvent?.id) {
  calResult = { status: 'ok', evento_id: calEvent.id, horario_confirmado: orig.horario_iso };
} else {
  calResult = {
    status: 'erro_calendar',
    mensagem: 'Tive problema para acessar a agenda. Vou te conectar com nossa equipe para confirmar o horário.'
  };
}

const allToolResults = [
  ...(orig.partialToolResults || []),
  { type: 'tool_result', tool_use_id: orig.toolUseId, content: JSON.stringify(calResult) }
];

const currentMessages = [...orig.messages, { role: 'user', content: allToolResults }];
const anthropicKey = $env.ANTHROPIC_API_KEY;

async function callAnthropic(msgs) {
  return fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': anthropicKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 1024, system: orig.fullSystem, messages: msgs }),
  });
}

let res;
try {
  res = await callAnthropic(currentMessages);
} catch (e) {
  await new Promise(r => setTimeout(r, 2000));
  try { res = await callAnthropic(currentMessages); }
  catch (e2) {
    return [{ json: { finalText: 'Aula agendada! Tive um problema técnico ao confirmar os detalhes — nossa equipe vai checar e confirmar por aqui.', remotejid } }];
  }
}

if (!res.ok) {
  return [{ json: { finalText: 'Aula agendada! Tive um problema técnico — nossa equipe vai confirmar por aqui.', remotejid } }];
}

const data = await res.json();
const finalText = data.content?.filter(b => b.type === 'text').map(b => b.text).join('') ||
  'Aula experimental agendada! Nossa equipe vai te esperar.';

return [{ json: { finalText, remotejid } }];
